n0:createOraclePackageSpec.n0:source:
CREATE OR REPLACE EDITIONABLE PACKAGE "%USER_NAME%"."MAXPRINT_UTILS_V2" AS

    FUNCTION GET_FILES_FROM_URL (
        P_URL IN VARCHAR2, 
        P_HTTP_METHOD IN VARCHAR2 DEFAULT 'GET', 
        P_USERNAME IN VARCHAR2 DEFAULT NULL, 
        P_PASSWORD IN VARCHAR2 DEFAULT NULL,
        P_PROXY_OVERRIDE   IN VARCHAR2 DEFAULT NULL,
        P_TRANSFER_TIMEOUT IN NUMBER   DEFAULT 180,
        P_WALLET_PATH      IN VARCHAR2 DEFAULT NULL,
        P_WALLET_PASSWORD  IN VARCHAR2 DEFAULT NULL
    ) RETURN CLOB;
    FUNCTION MAXPRINT_CALL (P_DYNAMIC_ACTION IN APEX_PLUGIN.T_DYNAMIC_ACTION, P_PLUGIN IN APEX_PLUGIN.T_PLUGIN) RETURN APEX_PLUGIN.T_DYNAMIC_ACTION_RENDER_RESULT;
    FUNCTION MAXPRINT_DA_AJAX (P_DYNAMIC_ACTION IN APEX_PLUGIN.T_DYNAMIC_ACTION, P_PLUGIN IN APEX_PLUGIN.T_PLUGIN) RETURN APEX_PLUGIN.T_DYNAMIC_ACTION_AJAX_RESULT;

END "MAXPRINT_UTILS_V2";
/
